head.script:
//-------------------------------------------------------------------------
// 추루 수정사항
// 저장 삭제 데이터 확인해야함
// cma 버튼 삭제
//-------------------------------------------------------------------------


//-------------------------------------------------------------------------
// 전역변수
//-------------------------------------------------------------------------
// hidden 컴포넌트 전역변수 선언
scwin.ed_fcrcBilgAmt = "";
scwin.ed_bilgAmtFcrc = "";
scwin.ed_crcCd = "";



scwin.strCurDate = WebSquare.date.getCurrentServerDate();  // 서버를 기준으로 현재 날짜 반환
scwin.arrParent = "";
scwin.isUpdate = "";

scwin.isChange = "";
scwin.isDelete = "";
scwin.sumDcGbn = "";
scwin.pgmId = "fs_202_05_07p.jsp"; // 프로그램ID


//-------------------------------------------------------------------------
// 화면 로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    $c.data.setPopupTitle("선사BILL 확정");

    scwin.isChange = false;
    scwin.isDelete = false;

    scwin.arrParent = $c.data.getParameter(); // 호출 화면에서 파라미터 받기

    ds_single.setJSON(scwin.arrParent.singleSet.getAllJSON(), true);
    ds_multi.setJSON(scwin.arrParent.multiSet.getAllJSON(), true);
    ds_orign.setJSON(scwin.arrParent.orignSet.getAllJSON(), true);

    if(ds_single_retrieve.getRowCount() != 0) {
        ds_single_retrieve.setJSON([]);
    }

    if(ds_multi_retrieve.getRowCount() != 0) {
        ds_multi_retrieve.setJSON([]);
    }

    if(ds_orign.getRowCount() != 0) {
        ds_orign_retrieve.setJSON([]);
    }

    ds_single_retrieve.setJSON(ds_single.getAllJSON(), true);
    ds_multi_retrieve.setJSON(ds_multi.getAllJSON(), true);
    ds_orign_retrieve.setJSON(ds_orign.getAllJSON(), true);

    scwin.isUpdate = scwin.arrParent.isUpdate;
    scwin.sumDcGbn = scwin.arrParent.sumDcGbn;

    ica_confirmDt.setValue(scwin.strCurDate);
    rd_adptExchRtInscrpYn.setValue("0");
    rd_billCoverPatternSeq.setValue("A");
    rd_slipCreatYn.setValue("1");
    ed_printPage.setValue("1");

    scwin.rd_slipCreatYn_onchange();


    // 소수점 표시여부에에 따른 소수점표시여부chk default 표시
    // 16으로 세팅하는건 asis가 잘못되어있어서 이렇게함
    ds_single.setCellData(0, "fmlaPatternCd", "16");
    if (ds_single.getCellData(0, "fmlaPatternCd") == "16") { // 청구서유형 CERTI(16) : CFS STUFFING
        cbx_dspDotYn.setValue("1");
    } else if (ds_single.getCellData(0, "cntrSizCd") != "") { // 컨테이너 Bill의 경우
        cbx_dspDotYn.setValue("");
    } else {
        cbx_dspDotYn.setValue("1");
    }

    if (ds_single.getCellData(0, "ediClntYn") == "Y") {
        rd_ediSndTrgtYn.setDisabled(false);
    } else {
        rd_ediSndTrgtYn.setDisabled(true);
    }
    rd_cmaSndYn.setDisabled(true);

    // Bill Title을 적요에 default Display - 20060627 taewon 
    ed_summary.setValue(ds_single.getCellData(0, "billTitleNm").substring(0, 25));

    $c.gus.cfEnableObj(ica_slipCloseYm, false);
    $c.gus.cfEnableObj(ica_taxCloseYm, false);
    $c.gus.cfEnableObj(ed_collMoneyAcctDeptCd, false);

    if (scwin.isUpdate) {
        scwin.f_UpdateRetrieve();
    } else {
        scwin.f_InsertRetrieve();
    }

    // 발행 체크박스 기본값 체크로 세팅
    cbx_printCheck.setValue("1");
    cbx_slipCheck.setValue("1");
    cbx_previewCheck.setValue("1");
    cbx_certiCheck.setValue("1");

};




//-------------------------------------------------------------------------
// 전자세금계산서 관련 URL header 추가, 호출화면 파라미터 전달값 유형에 따라 추후에 연결시 변경할 부분
//-------------------------------------------------------------------------
scwin.f_copyDataSetHeader = function (oOriginDataSet, oTargetDataSet) {
    let DsHeader = "";
    let colId = "";
    let colType = "";
    let colProp = "";
    let colSize = "";
    let addHeader = "url:STRING(1000),";

    for (i = 1; i <= oOriginDataSet.getTotalRow(); i++) {
        colId = oOriginDataSet.getColumnID(i);	     //column id
        let colIndex = oOriginDataSet.getColumnIndex(colId);  //column id에 해당하는 index값
        colSize = oOriginDataSet.getTotalCol(colIndex);//column size     

        /* column의 type 정의 코드

            Type  Description
            -----------------
                1    String
                2    Integer
                3    Decimal
                4    Date
                5    URL
        */



        //column type정의
        switch (oOriginDataSet.ColumnType(colIndex)) {
            case 1:
                colType = 'STRING';
                break;
            case 2:
                colType = 'INT';
                break;
            case 3:
                colType = 'DECIMAL';
                // 소수부에 대한 처리 추가
                if (oOriginDataSet.ColumnDec(colIndex) > 0)
                    colSize += "." + oOriginDataSet.ColumnDec(colIndex);
                break;
            case 4:
                colType = 'DATE';
                break;
            case 5:
                colType = 'URL';
                break;

            default:
                colType = "";

        }
        /* column의 property 정의
            0 : Normal (Key = No)
            1 : Constant
            2 : Key (Normal, Sequence)
            3 : Sequence (Key = No) // 현재 의미없음.
        */
        switch (oOriginDataSet.ColumnProp(i)) {
            case 0:
                colProp = "NORMAL";
                break;
            case 1:
                colProp = "CONSTANT";
                break;
            case 2:
                colProp = "KEYVALUE";
                break;
            default:
                colProp = "";
                break;
        }

        //column id,column type,column size, column property
        if (colId == 'url') continue;

        DsHeader = DsHeader + colId + ":" + colType + "(" + colSize + ")" + ":" + colProp + ",";
    }

    DsHeader = DsHeader + addHeader;

    DsHeader = DsHeader.substr(0, DsHeader.length - 1);
    oTargetDataSet.SetDataHeader(DsHeader);

    oTargetDataSet.ClearData();

    if (oOriginDataSet.getTotalRow() > 0) {
        let temp = oTargetDataSet.dataid;  // importdata를 한 후 DataSet의 기존의 dataid 속성값이 지워지는 것을 방지.
        oTargetDataSet.ImportData(oOriginDataSet.ExportData(1, oOriginDataSet.getTotalRow(), true));
        oTargetDataSet.dataid = temp;
    }
}


//-------------------------------------------------------------------------
// 화면종료시
//-------------------------------------------------------------------------
scwin.f_onUnload_onClick = function (e) {
    let arrRtnVal = "";

    if (scwin.isUpdate && scwin.isDelete) {
        arrRtnVal = "DELETE";
    } else if (scwin.isUpdate && scwin.isChange) {
        arrRtnVal = ds_bill.getCellData(0, "certiNo");
    } else {
        arrRtnVal = "NOCHANGE";
    }

    $c.win.closePopup(arrRtnVal);
};


//-------------------------------------------------------------------------
// BILL 생성 조회
//-------------------------------------------------------------------------
scwin.f_InsertRetrieve = function () {
    ds_single_retrieve.setCellData(0, "fmlaClsCd", "03");
    $c.sbm.execute(sbm_CertiCommon);
}

//-------------------------------------------------------------------------
// BILL 수정 조회 (데이터셋 확인 후 개발)
//-------------------------------------------------------------------------
scwin.f_UpdateRetrieve = function () {    

    dma_BillQueryCondition.set("bilgLodeptCd", ds_orign.getCellData(0, "bilgLodeptCd"));
    dma_BillQueryCondition.set("certiNo", ds_orign.getCellData(0, "upperCertiNo"));
    ds_single.setCellData(0, "fmlaClsCd", "03");

    $c.sbm.execute(sbm_BillCommon);

}



//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_save_onClick = async function (e) {
    if (ds_bill.getTotalRow() < 1) {
        $c.win.alert($c.data.getMessage(MSG_CM_WRN_001, "DATA"));
    }

    if (rd_slipCreatYn.getValue() == "1") {
        if ($c.gus.cfIsNull(ed_collMoneyAcctDeptCd.getValue())) {
            $c.win.alert("수금부서는 필수 입력 항목입니다. <br> [/공통/거래처/거래처관리] 화면에서 수금부서를 먼저 등록하세요..");
            return false;
        }
    }

    if (!await $c.gus.cfValidate([ed_billTitleNm, ica_confirmDt, ica_arDepPortDt, ed_collMoneyAcctDeptCd, ica_spplyDt, ica_slipDt, ed_summary, ica_bilgIntendDt])) {
        return;
    } else if (! await $c.gus.cfValidate([ed_billTitleNm, ica_confirmDt, ica_arDepPortDt, ica_bilgIntendDt])) {
        return;
    };
    //신고제외여부가 체크되었다면 E-mail은 필수 입력항목이 아니다.
    //전자세금계산서 반영
    /*
    if (!cbx_declarExceptYn.checked) {
        if (!cfValidate([ed_e0mail])) {
            return;
        }
    }
    */

    if (! await $c.win.confirm(MSG_CM_CRM_001)) {
        return;
    }

    ds_bill.setCellData(0, "confirmDt", ica_confirmDt.getValue());
    ds_bill.setCellData(0, "billTitleNm", ed_billTitleNm.getValue());
    ds_bill.setCellData(0, "subTitleNm1", ed_subTitleNm1.getValue());
    ds_bill.setCellData(0, "subTitleNm2", ed_subTitleNm2.getValue());
    ds_bill.setCellData(0, "subTitleNm3", ed_subTitleNm3.getValue());
    ds_bill.setCellData(0, "adptExchRtInscrpYn", rd_adptExchRtInscrpYn.getValue());
    ds_bill.setCellData(0, "wcrcDcsnClsCd", ed_wcrcDcsnClsCd.getValue());
    ds_bill.setCellData(0, "bilgExchRt", ed_bilgExchRt.getValue());
    ds_bill.setCellData(0, "inscrpBilgClntNm", ed_inscrpBilgClntNm.getValue());
    ds_bill.setCellData(0, "inscrpVsslEngNm", ed_inscrpVsslEngNm.getValue());
    ds_bill.setCellData(0, "inscrpPortcnt", ed_inscrpPortcnt.getValue());
    ds_bill.setCellData(0, "woNo", ed_woNo.getValue());
    ds_bill.setCellData(0, "arDepPortDt", ica_arDepPortDt.getValue());
    ds_bill.setCellData(0, "billCoverPatternSeq", rd_billCoverPatternSeq.getValue());
    ds_bill.setCellData(0, "certiPatternCd", "B");
    ds_bill.setCellData(0, "certiCnt", ds_multi_retrieve.getTotalRow());
    ds_bill.setCellData(0, "mainCertiNo", ds_bill.getCellData(0, "certiNo"));
    ds_bill.setCellData(0, "dcsnClsCd", "2");
    ds_bill.setCellData(0, "adptExchRt", ed_adptExchRt.getValue());
    ds_bill.setCellData(0, "crcCd", scwin.ed_crcCd);
    ds_bill.setCellData(0, "spplyAmt", ed_spplyAmt.getValue());
    ds_bill.setCellData(0, "spplyAmtFcrc", ed_spplyAmtFcrc.getValue());
    ds_bill.setCellData(0, "vatAmt", ed_vatAmt.getValue());
    ds_bill.setCellData(0, "totAmt", ed_sumAmt.getValue());
    ds_bill.setCellData(0, "bilgAmtFcrc", scwin.ed_bilgAmtFcrc);
    ds_bill.setCellData(0, "fcrcBilgAmt", scwin.ed_fcrcBilgAmt);
    ds_bill.setCellData(0, "bilgInscrpAmtFcrc", ed_bilgInscrpAmtFcrc.getValue());
    ds_bill.setCellData(0, "bilgAmt", ed_bilgAmt.getValue());
    ds_bill.setCellData(0, "pgmId", scwin.pgmId);
    ds_bill.setCellData(0, "bilgIntendDt", ica_bilgIntendDt.getValue());
    ds_bill.setCellData(0, "ediSndTrgtYn", rd_ediSndTrgtYn.getValue());

    ds_sellingEvidence.setCellData(0, "spplyDt", ica_spplyDt.getValue());
    ds_sellingEvidence.setCellData(0, "slipDt", ica_slipDt.getValue());
    ds_sellingEvidence.setCellData(0, "collMoneyAcctDeptCd", ed_collMoneyAcctDeptCd.getValue());
    ds_sellingEvidence.setCellData(0, "summary", ed_summary.getValue());
    ds_sellingEvidence.setCellData(0, "crcCd", scwin.ed_crcCd);
    ds_sellingEvidence.setCellData(0, "spplyAmt", ed_spplyAmt.getValue());
    ds_sellingEvidence.setCellData(0, "spplyAmtFcrc", ed_spplyAmtFcrc.getValue());
    ds_sellingEvidence.setCellData(0, "vatAmt", ed_vatAmt.getValue());
    ds_sellingEvidence.setCellData(0, "sumAmt", ed_sumAmt.getValue());
    ds_sellingEvidence.setCellData(0, "fmlaClsCd", "03");
    ds_sellingEvidence.setCellData(0, "fmlaPatternCd", ds_bill.getCellData(0, "fmlaPatternCd"));
    ds_sellingEvidence.setCellData(0, "receptClsCd", "02");
    ds_sellingEvidence.setCellData(0, "evidRglClsCd", "01");
    ds_sellingEvidence.setCellData(0, "slipCreatYn", rd_slipCreatYn.getValue());
    ds_sellingEvidence.setCellData(0, "certiCnt", ds_multi_retrieve.getTotalRow());
    ds_sellingEvidence.setCellData(0, "woNo", ed_woNo.getValue());



    if (scwin.ed_bilgAmtFcrc > 0) {
        ds_sellingEvidence.setCellData(0, "bilgAmtFcrc", scwin.ed_bilgAmtFcrc);
        ds_sellingEvidence.setCellData(0, "fcrcBilgAmt", scwin.ed_fcrcBilgAmt);
    } else {
        ds_sellingEvidence.setCellData(0, "bilgAmt", ed_bilgAmt.getValue());
    }

    //전자세금계산서 조회를 위한 URL 생성
    for (i = 0; i < ds_multi_retrieve.getTotalRow(); i++) {
        let odi1 = ds_bill.getCellData(0, "upperFmlaPatternCd");
        let odi2 = "";
        if (odi1 == "16") {
            odi2 = odi1;
        }

        let url = "";
        if (ds_bill.getCellData(0, "lineCd") == "ANL" && odi1 == "02") {
            url = scwin.f_createUrl("/ds/fs/fs_202_05_21_C" + odi1 + "A.ozr", "fs_202_05_21_C" + odi2 + ".odi", scwin.f_createParam(i));
        } else {
            url = scwin.f_createUrl("/ds/fs/fs_202_05_21_C" + odi1 + ".ozr", "fs_202_05_21_C" + odi2 + ".odi", scwin.f_createParam(i));
        }
        ds_multi_retrieve.setCellData(i, "url", url);
    }

    console.log("scwin.isupdate:"+scwin.isUpdate);
    if (scwin.isUpdate) {
        $c.sbm.execute(sbm_UpdateBill);
    } else {
        $c.sbm.execute(sbm_CreateBill);
    }

};

//-------------------------------------------------------------------------
// 전자세금계산서 발행시 보여질 레포트 URL 생성
// 예)
// ozrFileNm = "/ds/fs/fs_202_06_10_01_02.ozr"
// odiFileNm = "fs_202_06_10_01_02.odi"
// ozParam = "bilgLodeptCd=6A1,qryConKnd=2,...";
// URL이 최대 1000자가 넘어선 안된다.
//-------------------------------------------------------------------------
scwin.f_createUrl = function (ozrFileNm, odiFileNm, ozParam) {
    url = "http://ebiz.debis.co.kr/common/jsp/external_interface.jsp?"
        + "SYS_CD=OSIDE_CERTI&certiOzrFileNm=" + ozrFileNm
        + "&certiOdiFileNm=" + odiFileNm
        + "&certiOzParam=" + ozParam;

    return url;
}


//-------------------------------------------------------------------------
// 전자세금계산서 발행시 보여질 레포트 PARAM 생성
//-------------------------------------------------------------------------
scwin.f_createParam = function (idx) {
    let param = "";

    param = "certiNo=" + ds_multi_retrieve.getCellData(idx, "certiNo")
        + ",dspDotYn=" + (cbx_dspDotYn.getValue() == true ? "Y" : "N");


    return param;
}

