//-------------------------------------------------------------------------
// BILL 내역 setting
//-------------------------------------------------------------------------
scwin.f_pushBill = function () {
    console.log("Update 1 = "+scwin.isUpdate)
    if (ds_bill.getTotalRow() > 0) {
        if (scwin.isUpdate) {
                ed_certiNo.setValue(ds_bill.getCellData(0, "certiNo"));
                ica_confirmDt.setValue(ds_bill.getCellData(0, "confirmDt"));
                rd_adptExchRtInscrpYn.setValue(ds_bill.getCellData(0, "adptExchRtInscrpYn"));
            }
            ed_bilgExchRt.setValue(ds_bill.getCellData(0, "bilgExchRt"));
            ed_bilgInscrpAmtFcrc.setValue(ds_bill.getCellData(0, "bilgInscrpAmtFcrc"));
            ed_billTitleNm.setValue(ds_bill.getCellData(0, "billTitleNm"));
            ed_subTitleNm1.setValue(ds_bill.getCellData(0, "subTitleNm1"));
            ed_subTitleNm2.setValue(ds_bill.getCellData(0, "subTitleNm2"));
            ed_subTitleNm3.setValue(ds_bill.getCellData(0, "subTitleNm3"));
            ed_lineCd.setValue(ds_bill.getCellData(0, "lineCd"));
            ed_lineNm.setValue(ds_bill.getCellData(0, "lineNm"));


        ed_inscrpBilgClntNm.setValue(ds_bill.getCellData(0, "inscrpBilgClntNm"));
        ed_inscrpVsslCd.setValue(ds_bill.getCellData(0, "inscrpVsslCd"));
        ed_inscrpVsslNm.setValue(ds_bill.getCellData(0, "inscrpVsslNm"));
        ed_portcnt.setValue(ds_bill.getCellData(0, "portcnt"));
        ed_inscrpVsslEngNm.setValue(ds_bill.getCellData(0, "inscrpVsslEngNm") == "" ? ds_bill.getCellData(0, "inscrpVsslNm") : ds_bill.getCellData(0, "inscrpVsslEngNm"));

        if (ds_bill.getCellData(0, "inscrpPortcnt") == null || ds_bill.getCellData(0, "inscrpPortcnt") == "") {
            ed_inscrpPortcnt.setValue(ds_bill.getCellData(0, "portcnt"));
        } else {
            ed_inscrpPortcnt.setValue(ds_bill.getCellData(0, "inscrpPortcnt"));
        }
        ed_woNo.setValue(ds_bill.getCellData(0, "woNo"));
        ica_arDepPortDt.setValue(ds_bill.getCellData(0, "arDepPortDt"));
        ica_bilgIntendDt.setValue(ds_bill.getCellData(0, "bilgIntendDt"));
        rd_ediSndTrgtYn.setValue(ds_bill.getCellData(0, "ediSndTrgtYn"));

        if (ds_bill.getCellData(0, "lineCd") == "CMA" || ds_bill.getCellData(0, "lineCd") == "ANL") {
            rd_cmaSndYn.setValue(ds_bill.getCellData(0, "edisndclscd"));
        }

        // 추후 필수 확인 
        // rd_billCoverPatternSeq.Format   =   "A^A  ("+ds_bill.getCellData(0, "billCoverPatternNmA")
        //                                     +"),B^B  ("+ds_bill.getCellData(0, "billCoverPatternNmB")
        //                                     +"),C^C  ("+ds_bill.getCellData(0, "billCoverPatternNmC")+")";


        rd_billCoverPatternSeq.reset();
        rd_billCoverPatternSeq.setValue(ds_bill.getCellData(0, "billCoverPatternSeq"));
        ed_offsetVatNo.setValue(ds_bill.getCellData(0, "offsetVatNo"));
        ed_offsetBillNo.setValue(ds_bill.getCellData(0, "offsetBillNo"));
        ed_offsetNo.setValue(ds_bill.getCellData(0, "offsetNo"));
        ed_dcsnClsNm.setValue(ds_bill.getCellData(0, "dcsnClsNm"));
        ed_woNo.setValue(ds_bill.getCellData(0, "woNo"));

    }
}

//-------------------------------------------------------------------------
// BILL 발행 추후 OZreport 연결 후 사용
