scwin.btn_totalPrint_onClick = async function (e) {

    if (ed_certiNo.getValue().length < 1) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_049, "발행할 BILL내역"));
        return;
    }

    if (! await $c.win.confirm("발행 하시겠습니까?")) {
        return;
    }

    let oz = ds_bill.getCellData(0, "inscrpFmlaPatternCd");
    let fmlaPatternCd = ds_bill.getCellData(0, "fmlaPatternCd");
    let odi;
    let ozr;

    ds_bill.setCellData(0, "woNo", ed_woNo.getValue());
    odi = oz;

    if (fmlaPatternCd == "02" && (ds_bill.getCellData(0, "lineCd") == "APL" || ds_bill.getCellData(0, "lineCd") == "CNC" || ds_bill.getCellData(0, "lineCd") == "APN")) {
        //APL,CNC,APN 라인이고, BILL종류가 02 TS-PIER TO PIER 이면  다른 양식 사용 	
        ozr = odi + "_" + ds_bill.getCellData(0, "billCoverFmlaClsCd") + "N";
    } else if (oz == "04" && (ds_bill.getCellData(0, "lineCd") == "CMA" || ds_bill.getCellData(0, "lineCd") == "CNC" || ds_bill.getCellData(0, "lineCd") == "ANL")) {
        //CMA,CNC,ANL라인 표지 계좌번호 추가     
        ozr = odi + "_" + ds_bill.getCellData(0, "billCoverFmlaClsCd") + "2";
    } else if (oz == "04" && ds_bill.getCellData(0, "lineCd") == "SWIL") {
        //SWIL라인 표지 WO NO 추가
        ozr = odi + "_" + ds_bill.getCellData(0, "billCoverFmlaClsCd") + "3";
    } else if (oz == "04") {
        //기본 공통양식(04)
        ozr = odi + "_" + ds_bill.getCellData(0, "billCoverFmlaClsCd");
    } else {//개별양식(31,32)
        ozr = oz;
    }

    /* 
        쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
    */
    var ozMode = "";
    if (cbx_printCheck.getValue() == "1" && cbx_previewCheck.getValue() == "1") { // 인쇄옵션, 미리보기 둘다 체크된 경우
        ozMode = "preview";
    } else if (cbx_printCheck.getValue() == "1") { // 인쇄옵션만 체크된 경우
        ozMode = "print";
    } else if (cbx_previewCheck.getValue() == "1") { // 미리보기만 체크된 경우
        ozMode = "preview";
    }


    let dspDotYncheck = "";

    if (cbx_dspDotYn.getValue() == "1") {		// 소수점 표시유무
        dspDotYncheck = "Y";
    } else {
        dspDotYncheck = "N";
    }

    var data = {
        odiName: "fs_202_05_21_" + odi,
        reportName: "/ds/fs/fs_202_05_21_" + ozr + ".ozr",
        odiParam: {
            bilgLodeptCd: ds_bill.getCellData(0, "bilgLodeptCd"),
            certiNo: ds_bill.getCellData(0, "certiNo"),
            type: ds_bill.getCellData(0, "billCoverFmlaClsCd"),
            woNo: ds_bill.getCellData(0, "woNo"),
            dspDotYn: dspDotYncheck,
            sumDcGbn: scwin.sumDcGbn

        },
        viewerParam: {
            useprogressbar: false, // 프로그레스바 쓸지 말지
            zoom: 100, // 배율 설정
            mode: ozMode
        },
        formParam: {
            copies: ed_printPage.getValue()
        }
    };

    if( ozMode == "preview" ) {
        let opts = {
            id: "ozReportPopup",
            popupName: "오즈 리포트",
            modal: true,
            type: "browserPopup",
            width: 1000,
            height: 600,
            title: "오즈 리포트"
        };
        // $c.ext.openOzReport(data, opts);
        // await scwin.openPopup(data);
        await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
    } else if( ozMode == "print") {
        let opts = {
            "type": 'print',
            "printMode": 'view'
        };
        await $c.ext.printOzReport(data, opts);
    } else {
        await $c.ext.printOzReport(data, {});
    }

    let ozr2 = ds_bill.getCellData(0, "upperFmlaPatternCd");
    let odi2 = "fs_202_05_21_C";
    if (ozr2 == "16") {
        odi2 = odi2 + ozr2;
    }

    //합계표시 유무
    if (cbx_dspTotAmt.checked) {
        dspToAmtCheck = "Y";
    } else {
        dspToAmtCheck = "N";
    }

    if (cbx_certiCheck.getValue() == "1" && ozr2 != null && ozr2 != "") {

        // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
        var data2 = {
            odiName: odi2,
            reportName: "/ds/fs/fs_202_05_21_" + ozr + ".ozr",
            odiParam: {
                certiNo: ds_bill.getCellData(0, "certiNo"),
                upperFmlaPatternCd: ds_bill.getCellData(0, "upperFmlaPatternCd"),
                dspToAmt: dspToAmtCheck,

            },
            viewerParam: {
                useprogressbar: false, // 프로그레스바 쓸지 말지
                zoom: 100, // 배율 설정
                mode: ozMode
            },
            formParam: {
                copies: ed_printPage.getValue()
            }
        };

        // ALN 라인이고, BILL 종류가  TS-PIER TO PIER 이면  BL_NO 추가 양식으로  CERTI 발행 한다. 
        if (ds_bill.getCellData(0, "lineCd") == "ANL" && ozr2 == "02") {

            data2.reportName = "/ds/fs/fs_202_05_21_C" + ozr2 + "A" + ".ozr";
        } else if (ds_bill.getCellData(0, "lineCd") == "APL" && (ozr2 == "02" || ozr2 == "04")) {

            data2.reportName = "/ds/fs/fs_202_05_21_C" + ozr2 + "P" + ".ozr";
        } else if ((ds_bill.getCellData(0, "lineCd") == "ANL" || ds_bill.getCellData(0, "lineCd") == "CMA") && ozr2 == "05") {

            data2.reportName = "/ds/fs/fs_202_05_21_C" + ozr2 + "A" + ".ozr";
        } else if ((ds_bill.getCellData(0, "lineCd") == "ANL" || ds_bill.getCellData(0, "lineCd") == "CMA") && ozr2 == "01") {

            data2.reportName = "/ds/fs/fs_202_05_21_C" + ozr2 + "A" + ".ozr";
        } else {

            data2.reportName = "/ds/fs/fs_202_05_21_C" + ozr2 + ".ozr";
        }

        if( ozMode == "preview" ) {
            let opts = {
                id: "ozReportPopup",
                popupName: "오즈 리포트",
                modal: true,
                type: "browserPopup",
                width: 1000,
                height: 600,
                title: "오즈 리포트"
            };
            await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data2);
        } else if( ozMode == "print") {
            let opts = {
                "type": 'print',
                "printMode": 'view'
            };
            await $c.ext.printOzReport(data2, opts);
        } else {
            await $c.ext.printOzReport(data2, {});
        }

    }

    //세금계산서
    if (cbx_slipCheck.getValue() == "1" && ds_sellingEvidence.getCellData(0, "sellVatNo") != "" && ds_sellingEvidence.getCellData(0, "taxnClsCd") != "03") {
        var data3 = {
            odiName: "fi_401_01_02p",
            reportName: "/ac/fi/taxbiz/vatctrl/fi_401_01_02p.ozr",
            odiParam: {
                pchsSellCls: ds_sellingEvidence.getCellData(0, "sellVatNo"),
                upperFmlaPatternCd: ds_bill.getCellData(0, "upperFmlaPatternCd"),
                dspToAmt: dspToAmtCheck,

            },
            viewerParam: {
                useprogressbar: false, // 프로그레스바 쓸지 말지
                zoom: 100, // 배율 설정
                mode: ozMode
            },
            formParam: {
                copies: "1"
            }
        };

        if( ozMode == "preview" ) {
            let opts = {
                id: "ozReportPopup",
                popupName: "오즈 리포트",
                modal: true,
                type: "browserPopup",
                width: 1000,
                height: 600,
                title: "오즈 리포트"
            };
            await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data3);
        } else if( ozMode == "print") {
            let opts = {
                "type": 'print',
                "printMode": 'view'
            };
            await $c.ext.printOzReport(data3, opts);
        } else {
            await $c.ext.printOzReport(data3, {});
        }
    }
};

